const { status, nome, resumo, horario, whatsapp, tipo_erro } = $input.item.json;

if (!whatsapp) {
  throw new Error('whatsapp_destinatario vazio para cliente: ' + nome);
}

let header;
if (status === 'sucesso') {
  header = '✅ PLANILHA ATUALIZADA';
} else if (status === 'parcial') {
  header = '⚠️ PLANILHA COM ALERTAS';
} else {
  const icones = { credencial: '🔐', rede: '🌐', planilha: '📊', generico: '⚠️' };
  header = (icones[tipo_erro] || '⚠️') + ' FALHA NA AUTOMAÇÃO';
}

const body = status === 'sucesso'
  ? `O preenchimento da planilha de cobrança foi concluído.\n${resumo ? resumo + '\n' : ''}`
  : `Erro: ${resumo}\n`;

const text = `${header}\n\nCliente: ${nome}\n${body}Horário: ${horario}`;

return [{ json: { whatsapp, text, nome, status } }];
